const p = msg.payload || {};

function num(v) {
    const n = Number(v);
    return Number.isFinite(n) ? n : 0;
}

function esc(s) {
    return String(s ?? '').replace(/\\/g, '\\\\').replace(/'/g, "\\'");
}

const did = String(p.device_id || p.id_device || '').trim();
if (!did) return null;

const t = num(p.temperature);
const h = num(p.humidity);
const c = num(p.co2);
const l = num(p.light);
const v = num(p.voltage);
const a = num(p.current);
const f = num(p.frequency);
const pw = num(p.power);

msg.topic = `
INSERT INTO sensor_data
(device_id, temperature, humidity, co2, light, voltage, current, frequency, power)
VALUES
('${esc(did)}', ${t}, ${h}, ${c}, ${l}, ${v}, ${a}, ${f}, ${pw})
`;

return msg;

let t = msg.payload.type;
let f = msg.payload.filter;
let did = msg.payload.device_id || '';
let sql = '';

// Tự động tính offset: chuyển timestamp về giờ VN (+7 UTC)
// bù trừ timezone của MySQL server bất kể server đang ở múi giờ nào
const vnTs = `(timestamp + INTERVAL (7*3600 - TIME_TO_SEC(TIMEDIFF(NOW(), UTC_TIMESTAMP()))) SECOND)`;
const vnNow = `(UTC_TIMESTAMP() + INTERVAL 7 HOUR)`;

if (f === 'day') {
    sql = `SELECT DATE_FORMAT(${vnTs}, '%H:%i') as time_label, ${t} as value FROM sensor_data WHERE device_id = '${did}' AND DATE(${vnTs}) = DATE(${vnNow}) ORDER BY timestamp ASC`;
} else if (f === 'month') {
    sql = `SELECT DATE_FORMAT(${vnTs}, '%d/%m') as time_label, AVG(${t}) as value FROM sensor_data WHERE device_id = '${did}' AND MONTH(${vnTs}) = MONTH(${vnNow}) AND YEAR(${vnTs}) = YEAR(${vnNow}) GROUP BY DATE(${vnTs}) ORDER BY timestamp ASC`;
} else if (f === 'year') {
    sql = `SELECT DATE_FORMAT(${vnTs}, '%m/%Y') as time_label, AVG(${t}) as value FROM sensor_data WHERE device_id = '${did}' AND YEAR(${vnTs}) = YEAR(${vnNow}) GROUP BY MONTH(${vnTs}) ORDER BY timestamp ASC`;
}

msg.topic = sql;
msg.socketId = msg._socketId;
return msg;

let outMsg = {
    _socketId: msg.socketId,
    topic: 'history_response',
    payload: msg.payload
};
return outMsg;

node.warn('MySQL Error: ' + (msg.error && msg.error.message ? msg.error.message : JSON.stringify(msg.error)));
if (msg.socketId) {
    let reqType = msg.reqType || '';
    let topic = 'auth_response';
    if (reqType === 'area_create') topic = 'area_create_response';
    else if (reqType === 'control_unit_insert' || reqType === 'room_insert') topic = 'control_unit_create_response';
    else if (reqType === 'room_delete') topic = 'room_delete_response';
    else if (reqType === 'room_list') topic = 'room_list_response';
    else if (reqType === 'room_device_add') topic = 'sensor_device_add_response';
    else if (reqType === 'room_devices_list') topic = 'room_devices_list_response';
    return {
        _socketId: msg.socketId,
        topic: topic,
        payload: { status: 'error', message: 'Lỗi cơ sở dữ liệu: ' + (msg.error && msg.error.message ? msg.error.message : 'không xác định') }
    };
}
return null;

const p = msg.payload || {};
const reqTopic = msg.topic || '';
const gw = String(p.control_id || p.gateway_id || p.ma_tu || p.gatewayId || 'ESP79').trim();

function makeId(prefix) {
    return prefix + '_' + Date.now() + '_' + Math.floor(Math.random() * 10000);
}
function bool01(v, defVal = true) {
    if (v === undefined || v === null || v === '') return defVal;
    if (v === true || v === 1 || v === '1' || String(v).toLowerCase() === 'true') return true;
    return false;
}
function intVal(v, defVal = 0) {
    const n = parseInt(v, 10);
    return Number.isFinite(n) ? n : defVal;
}
function floatVal(v, defVal = 0) {
    const n = parseFloat(v);
    return Number.isFinite(n) ? n : defVal;
}
function upper(v, defVal = '') {
    return String(v === undefined || v === null || v === '' ? defVal : v).trim().toUpperCase();
}

let out = {};

// UI có thể gửi sẵn một lệnh đầy đủ; Node-RED chỉ bổ sung mã lệnh và yêu cầu phản hồi khi cần.
if (reqTopic === 'stm32_cmd_request') {
    out = Object.assign({}, p);
    if (!out.type) out.type = 'CMD';
    if (out.ack_req === undefined) out.ack_req = true;
    if (!out.msg_id) out.msg_id = makeId('NR_CMD');
}
else if (reqTopic === 'mode_request') {
    const mode = upper(p.mode || p.value, 'MANUAL');
    out = { msg_id: p.msg_id || makeId('NR_MODE'), type: 'CMD', cmd: 'SET_MODE', ack_req: bool01(p.ack_req, true), mode, data: { mode } };
}
else if (reqTopic === 'relay_request') {
    const relay = intVal(p.relay, 1);
    const state = intVal(p.state, 0) ? 1 : 0;
    out = { msg_id: p.msg_id || makeId('NR_RELAY'), type: 'CMD', cmd: 'SET_RELAY', ack_req: bool01(p.ack_req, true), mode: 'MANUAL', relay, state, data: { mode: 'MANUAL', relay, state } };
}
else if (reqTopic === 'timer_request') {
    const relay = intVal(p.relay, 1);
    out = { msg_id: p.msg_id || makeId('NR_TIMER'), type: 'CMD', cmd: 'SET_TIMER', ack_req: bool01(p.ack_req, true), relay };
    if (Array.isArray(p.schedules)) {
        out.data = { relay, schedules: p.schedules.map((s, i) => ({ index: intVal(s.index, i + 1), enable: intVal(s.enable, 0) ? 1 : 0, on: String(s.on || '00:00'), off: String(s.off || '00:00') })) };
    } else {
        out.index = intVal(p.index, 1);
        out.enable = intVal(p.enable, 0) ? 1 : 0;
        out.on = String(p.on || p.on_time || '00:00');
        out.off = String(p.off || p.off_time || '00:00');
        out.data = { relay: out.relay, index: out.index, enable: out.enable, on: out.on, off: out.off };
    }
}
else if (reqTopic === 'sensor_rule_request') {
    const relay = intVal(p.relay, 1);
    const logic = upper(p.logic || p.op, 'ABOVE');
    const idDevice = String(p.id_device || p.device_id || p.device || '').trim();
    const field = String(p.field || p.metric || 'temperature').trim();
    const enable = intVal(p.enable, 1) ? 1 : 0;
    out = { msg_id: p.msg_id || makeId('NR_SENSOR'), type: 'CMD', cmd: 'SET_SENSOR_RULE', ack_req: bool01(p.ack_req, true), relay, enable, id_device: idDevice, field, logic: (logic === 'BELOW' || logic === '<' || logic === '<=') ? 'BELOW' : 'ABOVE' };
    if (out.logic === 'ABOVE') {
        const onAbove = floatVal(p.onAbove ?? p.onValue ?? p.value, 0);
        const offBelow = floatVal(p.offBelow ?? p.offValue, onAbove - 5);
        out.onAbove = onAbove;
        out.offBelow = offBelow;
        out.onValue = onAbove;
        out.offValue = offBelow;
        out.data = { relay, enable, id_device: idDevice, field, logic: out.logic, onAbove, offBelow, onValue: onAbove, offValue: offBelow };
    } else {
        const onBelow = floatVal(p.onBelow ?? p.onValue ?? p.value, 0);
        const offAbove = floatVal(p.offAbove ?? p.offValue, onBelow + 5);
        out.onBelow = onBelow;
        out.offAbove = offAbove;
        out.onValue = onBelow;
        out.offValue = offAbove;
        out.data = { relay, enable, id_device: idDevice, field, logic: out.logic, onBelow, offAbove, onValue: onBelow, offValue: offAbove };
    }
}
else if (reqTopic === 'fan_request') {
    out = { msg_id: p.msg_id || makeId('NR_FAN'), type: 'CMD', cmd: 'SET_FAN', ack_req: bool01(p.ack_req, true), data: {} };
    if (p.fan !== undefined) { out.fan = intVal(p.fan, 0) ? 1 : 0; out.data.fan = out.fan; }
    else { out.fanMode = intVal(p.fanMode, 1); out.data.fanMode = out.fanMode; }
}
else if (reqTopic === 'fan_threshold_request') {
    const fanOnTemp = floatVal(p.fanOnTemp ?? p.fan_on ?? p.onTemp, 35);
    const fanOffTemp = floatVal(p.fanOffTemp ?? p.fan_off ?? p.offTemp, 30);
    out = { msg_id: p.msg_id || makeId('NR_FAN_TH'), type: 'CMD', cmd: 'SET_FAN_THRESHOLD', ack_req: bool01(p.ack_req, true), fanOnTemp, fanOffTemp, data: { fanOnTemp, fanOffTemp } };
}
else if (reqTopic === 'status_request') out = { msg_id: p.msg_id || makeId('NR_STATUS'), type: 'CMD', cmd: 'GET_STATUS', ack_req: true };
else if (reqTopic === 'full_state_request') out = { msg_id: p.msg_id || makeId('NR_FULL'), type: 'CMD', cmd: 'GET_FULL_STATE', ack_req: true };
else if (reqTopic === 'save_flash_request') out = { msg_id: p.msg_id || makeId('NR_FLASH'), type: 'CMD', cmd: 'SAVE_FLASH', ack_req: true };
else if (reqTopic === 'sync_request') out = { msg_id: p.msg_id || makeId('NR_SYNC'), type: 'CMD', cmd: 'CONFIG_SYNC_REQUEST', ack_req: true };
else if (reqTopic === 'device_list_cmd_request') out = { msg_id: p.msg_id || makeId('NR_DEV'), type: 'CMD', cmd: 'GET_DEVICE_LIST', ack_req: true };
else return null;

out.gateway_id = gw;
out.control_id = gw;
msg.topic = `maydokhongkhi/${gw}/stm32/cmd`;
msg.payload = out;
return msg;

const p = msg.payload || {};
const topic = msg.topic || '';
const parts = topic.split('/');
const gw = String(p.control_id || p.gateway_id || (parts.length >= 2 ? parts[1] : 'ESP79')).trim();
if (!p.gateway_id) p.gateway_id = gw;
if (!p.control_id) p.control_id = gw;

let uiTopic = 'stm32_message';
if (topic.endsWith('/ack')) uiTopic = 'stm32_ack';
else if (topic.endsWith('/relay/state')) uiTopic = 'relay_state';
else if (topic.endsWith('/status')) uiTopic = 'stm32_status';
else if (topic.endsWith('/config/state')) uiTopic = 'config_state';
else if (topic.endsWith('/full_state')) uiTopic = 'full_state';
else if (topic.endsWith('/fan/state')) uiTopic = 'fan_state';
else if (topic.endsWith('/boot')) uiTopic = 'stm32_boot';
else if (topic.endsWith('/config/sync/request') || topic.endsWith('/sync/request')) uiTopic = 'sync_request_from_stm32';

const uiMsg = { topic: uiTopic, payload: p };
let ackMsg = null;
const needAck = (p.ack_req === true || p.ack_req === 1 || p.ack_req === '1' || p.ackReq === true);
if (needAck && p.msg_id) {
    ackMsg = { topic: `maydokhongkhi/${gw}/server/ack`, payload: { type: 'ACK', ack_for: p.msg_id, status: 'OK', message: 'Node-RED đã nhận dữ liệu từ tủ', from: 'Node-RED', gateway_id: gw, control_id: gw, timestamp_ms: Date.now() } };
}
let dbMsg = null;
if (uiTopic === 'relay_state' || uiTopic === 'config_state' || uiTopic === 'fan_state' || uiTopic === 'stm32_status' || uiTopic === 'full_state') dbMsg = { topic: 'store_stm_state', payload: p };
let syncMsg = null;
if (uiTopic === 'sync_request_from_stm32' || p.type === 'CONFIG_SYNC_REQUEST') syncMsg = { topic: 'config_sync_sql', payload: p, req: { gateway_id: gw, control_id: gw, msg_id: p.msg_id || '', localCfgVersion: p.localCfgVersion || 0 } };
return [uiMsg, ackMsg, dbMsg, syncMsg];

const topic = msg.topic || '';
const p = msg.payload || {};
const parts = topic.split('/');
const gw = p.gateway_id || (parts.length >= 2 ? parts[1] : 'ESP79');
if (!p.gateway_id) p.gateway_id = gw;

let uiTopic = 'gateway_message';
if (topic.endsWith('/status')) uiTopic = 'gateway_status';
else if (topic.endsWith('/ack')) uiTopic = 'gateway_ack';
else if (topic.endsWith('/devices/request')) uiTopic = 'gateway_device_request';
else if (topic.endsWith('/devices/response')) uiTopic = 'gateway_device_response';
return { topic: uiTopic, payload: p };

const p = msg.payload || {};
const parts = String(msg.topic || '').split('/');
const controlId = String(p.control_id || p.gateway_id || (parts.length >= 2 ? parts[1] : 'ESP79')).trim();
function esc(s) { return String(s ?? '').replace(/\\/g, '\\\\').replace(/'/g, "\\'"); }
msg.req = { msg_id: p.msg_id || '', gateway_id: controlId, control_id: controlId };
msg.topic = `SELECT cud.sensor_device_id AS device_id, COALESCE(sd.device_name, cud.sensor_device_id) AS device_name, cud.control_id AS gateway_id, cud.control_id AS control_id, sd.fields_json FROM control_unit_devices cud LEFT JOIN sensor_devices sd ON sd.username=cud.username AND sd.device_id=cud.sensor_device_id WHERE cud.control_id='${esc(controlId)}' ORDER BY cud.sensor_device_id ASC`;
return msg;

const req = msg.req || {};
const gw = req.control_id || req.gateway_id || 'ESP79';
const rows = Array.isArray(msg.payload) ? msg.payload : [];
const seen = {};
const devices = [];

for (const r of rows) {
    const id = String(r.device_id || r.id_device || '').trim();
    if (!id || seen[id]) continue;
    seen[id] = true;
    let fields = ['temperature','humidity','co2','light','voltage','current','frequency','power'];
    try { if (r.fields_json) fields = JSON.parse(r.fields_json); } catch(e) {}
    devices.push({
        id: id,
        id_device: id,
        name: r.device_name || id,
        topic: `maydokhongkhi/${id}/data`,
        fields: fields
    });
}

msg.topic = `maydokhongkhi/${gw}/gateway/devices/response`;
msg.payload = {
    msg_id: req.msg_id || ('NR_DEVRES_' + Date.now()),
    type: 'DEVICE_LIST_RESPONSE',
    gateway_id: gw,
    control_id: gw,
    status: 'OK',
    count: devices.length,
    devices: devices
};
return msg;

const p = msg.payload || {};
function esc(s) {
    return String(s ?? '').replace(/\\/g, '\\\\').replace(/'/g, "\\'");
}
function pad2(n) { return String(n).padStart(2, '0'); }
function todayYmd() {
    const d = new Date();
    return `${d.getFullYear()}-${pad2(d.getMonth() + 1)}-${pad2(d.getDate())}`;
}
function lastDay(y, m) {
    return new Date(Number(y), Number(m), 0).getDate();
}
function error(message) {
    return [null, {
        _socketId: msg._socketId,
        topic: 'usage_response',
        payload: { status: 'error', message }
    }];
}

const allowedMetrics = ['energy_kwh', 'temperature', 'humidity', 'co2', 'light', 'voltage', 'current', 'frequency', 'power'];
const allowedPeriods = ['day', 'month', 'year'];
const did = String(p.device_id || p.id_device || '').trim();
if (!did) return error('Thiếu device_id để thống kê.');

const metric = allowedMetrics.includes(p.metric) ? p.metric : 'energy_kwh';
const period = allowedPeriods.includes(p.period) ? p.period : 'day';
const sampleSec = Math.max(1, Math.min(3600, Number(p.sample_sec || p.sampleSec || 60)));
const maxGapSec = Math.max(10, Math.min(86400, Number(p.max_gap_sec || p.maxGapSec || 900)));
let date = String(p.date || '').trim();
let start = '', end = '';

if (period === 'day') {
    if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) date = todayYmd();
    start = `${date} 00:00:00`;
    end = `${date} 23:59:59`;
} else if (period === 'month') {
    if (!/^\d{4}-\d{2}$/.test(date)) date = todayYmd().slice(0, 7);
    const [y, m] = date.split('-');
    start = `${y}-${m}-01 00:00:00`;
